import React from "react";
import {Modal, Pressable, ScrollView, StyleSheet, View} from "react-native";
import Animated, {FadeIn, ZoomIn} from "react-native-reanimated";
import {Icon, Text} from "../../../";
import type {IKitsDialogControlled} from "@lmb/kitsconcerto-types";
import {useKitsTheme} from "../../../Contexts/Theme";
import {useSeverityColors} from "../../../Hooks/useSeverityColors";

export default function KitsDialogControlled({state, onHide}: IKitsDialogControlled) {
    const {children, onClose, asyncClose, type, icon, ...rest} = state;
    const {resolveToken, theme} = useKitsTheme();
    const colors = type ? useSeverityColors(type) : null;

    const surfaceColor = resolveToken('surface-card');
    const textColor = resolveToken('text');
    const borderColor = colors?.border ?? resolveToken('border');
    const subtextColor = resolveToken('gray.500');
    const brandLogo = type === 'brand' ? theme.config.logo : null;

    const hide = async () => {
        if (asyncClose && typeof onClose === "function") {
            await onClose();
        } else {
            onClose?.();
        }
        onHide();
    };

    if (!state.visible) return null;

    const content = typeof children === "function" ? children(hide) : children;

    return (
        <Modal visible transparent animationType="none" onRequestClose={hide}>
            <Animated.View entering={FadeIn.duration(200)} style={styles.overlay}>
                <Pressable style={StyleSheet.absoluteFill} onPress={hide}/>
                <Animated.View
                    entering={ZoomIn.springify().damping(40).stiffness(300)}
                    style={[
                        styles.panel,
                        {backgroundColor: surfaceColor, borderColor},
                        rest.contentStyle,
                    ]}
                >
                    {/* Severity accent strip */}
                    {colors && (
                        <View style={{height: 4, backgroundColor: colors.solid, borderTopLeftRadius: 16, borderTopRightRadius: 16}}/>
                    )}

                    {/* Header */}
                    {rest.header != null && (
                        <View style={[styles.header, {borderBottomColor: borderColor}]}>
                            {/* Inline severity icon */}
                            {(icon || brandLogo) && colors && (
                                <View style={{
                                    width: 36,
                                    height: 36,
                                    borderRadius: 18,
                                    backgroundColor: colors.iconBg,
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    marginRight: 12,
                                }}>
                                    {brandLogo ? brandLogo : typeof icon === 'string' ? (
                                        <Icon name={icon as never} size={'lg'} color={colors.iconFg}/>
                                    ) : icon}
                                </View>
                            )}
                            <Text style={{fontSize: 18, fontWeight: "700", color: textColor, flex: 1}}>
                                {rest.header as React.ReactNode}
                            </Text>
                            <Pressable onPress={hide} hitSlop={8}>
                                <Text style={{fontSize: 18, color: subtextColor}}>✕</Text>
                            </Pressable>
                        </View>
                    )}

                    {/* Body */}
                    <ScrollView
                        style={styles.body}
                        contentContainerStyle={styles.bodyContent}
                        showsVerticalScrollIndicator={false}
                    >
                        {content}
                    </ScrollView>

                    {/* Footer */}
                    {rest.footer != null && (
                        <View style={[styles.footer, {borderTopColor: borderColor}]}>
                            {rest.footer as React.ReactNode}
                        </View>
                    )}
                </Animated.View>
            </Animated.View>
        </Modal>
    );
}

const styles = StyleSheet.create({
    overlay: {
        flex: 1,
        backgroundColor: "rgba(0,0,0,0.45)",
        justifyContent: "center",
        alignItems: "center",
        padding: 24,
    },
    panel: {
        borderRadius: 16,
        borderWidth: 1,
        width: "100%",
        maxHeight: "80%",
        overflow: "hidden",
        elevation: 12,
        shadowColor: "#000",
        shadowOffset: {width: 0, height: 6},
        shadowOpacity: 0.2,
        shadowRadius: 12,
    },
    header: {
        flexDirection: "row",
        alignItems: "center",
        paddingHorizontal: 20,
        paddingVertical: 16,
        borderBottomWidth: 1,
    },
    body: {
        maxHeight: 400,
    },
    bodyContent: {
        padding: 20,
    },
    footer: {
        flexDirection: "row",
        justifyContent: "flex-end",
        paddingHorizontal: 20,
        paddingVertical: 12,
        borderTopWidth: 1,
        gap: 8,
    },
});
